// src/lib/utils.test.ts
import { describe, it, expect } from 'vitest';
import { normalizeAddress, generateRedfinUrl, generateMapsUrl } from './utils';

describe('normalizeAddress', () => {
  it('should convert common abbreviations to lowercase', () => {
    expect(normalizeAddress('123 Main St')).toBe('123 main street');
    expect(normalizeAddress('456 Oak Ave')).toBe('456 oak avenue');
  });

  it('should handle multiple spaces', () => {
    expect(normalizeAddress('123  Main   St')).toBe('123 main street');
  });

  it('should handle empty string', () => {
    expect(normalizeAddress('')).toBe('');
  });

  it('should preserve case for words not in abbreviation map', () => {
    expect(normalizeAddress('123 MAIN STREET')).toBe('123 main street'); // abbreviations lowercased
    expect(normalizeAddress('123 Main XYX')).toBe('123 main xyx'); // unknown stays as-is
  });

  it('should handle addresses with numbers', () => {
    expect(normalizeAddress('456 Oak Ave Apt 2')).toBe('456 oak avenue apartment 2');
  });

  it('should handle suite abbreviations', () => {
    expect(normalizeAddress('123 Main Ste 100')).toBe('123 main suite 100');
  });
});

describe('generateRedfinUrl', () => {
  it('should encode special characters', () => {
    const url = generateRedfinUrl('123 Main St', 'City', 'CA', '12345');
    expect(url).toContain('encodeURIComponent');
    expect(url).not.toContain('='); // = is CSV injection char
  });

  it('should handle missing optional params', () => {
    const url = generateRedfinUrl('123 Main St');
    expect(url).toContain('123+Main+St');
  });
});

describe('generateMapsUrl', () => {
  it('should encode addresses with special chars', () => {
    const url = generateMapsUrl('123=Oak+St');
    expect(url).toContain('encodeURIComponent');
  });
});
