      method: 'POST',
      body: JSON.stringify({ name: 'Test', email: 'test@test.com', password: 'abcdefg1!' }),
    });
    const res = await POST(req);
    expect(res.status).toBe(400);
  });

  it('should return 400 for weak password - no special char', async () => {
    const req = new NextRequest('http://localhost/api/auth/register', {
      method: 'POST',
      body: JSON.stringify({ name: 'Test', email: 'test@test.com', password: 'Abcdefg1' }),
    });
    const res = await POST(req);
    expect(res.status).toBe(400);
  });

  it('should return 409 for duplicate email', async () => {
    const { prisma } = await import('@/lib/prisma');
    prisma.user.findUnique.mockResolvedValue({ id: 'existing' });
    const req = new NextRequest('http://localhost/api/auth/register', {
      method: 'POST',
      body: JSON.stringify({ name: 'Test', email: 'existing@test.com', password: 'Abcdefg1!' }),
    });
    const res = await POST(req);
    expect(res.status).toBe(409);
  });

  it('should assign ADMIN role to first user', async () => {
    const { prisma } = await import('@/lib/prisma');
    prisma.user.findUnique.mockResolvedValue(null);
    prisma.user.count.mockResolvedValue(0); // first user
    prisma.user.create.mockResolvedValue({ id: '1', role: 'ADMIN', name: 'Test', email: 'test@test.com' });
    const req = new NextRequest('http://localhost/api/auth/register', {
      method: 'POST',
      body: JSON.stringify({ name: 'Test', email: 'test@test.com', password: 'Abcdefg1!' }),
    });
    const res = await POST(req);
    const body = await res.json();
    expect(body.role).toBe('ADMIN');
  });
});
